uint256 signerVotingPowerBps = uint256(
    party.getVotingPowerAt(signer, uint40(block.timestamp), type(uint256).max)
) * 10000;

if (signerVotingPowerBps == 0 && party.balanceOf(signer) == 0) {
    // Must own a party card or be delegated voting power
    revert NotMemberOfParty();
}

uint96 totalVotingPower = party.getGovernanceValues().totalVotingPower;
uint96 thresholdBps = signingThresholdBps[party];

// Either threshold is 0 or signer votes above threshold
if (thresholdBps == 0 || (signerVotingPowerBps / totalVotingPower >= thresholdBps)) {
    return IERC1271.isValidSignature.selector;
}

if ((totalSupplyHistory.length == 0) || (totalSupplyHistory[0].fromBlock > _blockNumber)) {
    if (address(parentToken) != 0) {
        return parentToken.totalSupplyAt(min(_blockNumber, parentSnapShotBlock));
    } else {
        return 0;
    }

// This will return the expected totalSupply during normal situations
} else {
    return getValueAt(totalSupplyHistory, _blockNumber);
}

if ((checkpoints.length == 0) || (checkpoints[checkpoints.length - 1].fromBlock < block.number)) {
    Checkpoint storage newCheckPoint = checkpoints[checkpoints.length++];
    newCheckPoint.fromBlock = uint128(block.number);
    newCheckPoint.value = uint128(_value);
} else {
    Checkpoint storage oldCheckPoint = checkpoints[checkpoints.length - 1];
    oldCheckPoint.value = uint128(_value);
}

for (uint256 i = 0; i < proof.length; i++) {
    bytes32 proofElement = proof[i];

    if (computedHash <= proofElement) {
        // Hash(current computed hash + current element of the proof)
        computedHash = keccak256(abi.encodePacked(computedHash, proofElement));
    } else {
        // Hash(current element of the proof + current computed hash)
        computedHash = keccak256(abi.encodePacked(proofElement, computedHash));
    }
}

if (address(creatorFeeManager) != address(0)) {
    (creator, creatorFeeAmount) = creatorFeeManager.viewCreatorFeeInfo(collection, price, itemIds);

    if (creator == address(0)) {
        // If recipient is null address, creator fee is set to 0
        creatorFeeAmount = 0;
    } else if (creatorFeeAmount * ONE_HUNDRED_PERCENT_IN_BP > (price * uint256(maxCreatorFeeBp))) {
        // If creator fee is higher than tolerated, it reverts
        revert CreatorFeeBpTooHigh();
    }
}

if (functionSelector == StrategyReservoirCollectionOffer.executeCollectionStrategyWithTakerAsk.selector) {
    if (makerBid.additionalParameters.length != 32) {
        return (isValid, OrderInvalid.selector);
    } else {
        uint256 transferCooldownPeriod = abi.decode(makerBid.additionalParameters, (uint256));

        // @dev It returns OrderInvalid even if a custom error exists (for order invalidation purposes).
        if (transferCooldownPeriod > MAXIMUM_TRANSFER_COOLDOWN_PERIOD) {
            return (isValid, OrderInvalid.selector);
        }
    }
}

if (
    functionSelector == StrategyReservoirCollectionOffer.executeCollectionStrategyWithTakerAskWithProof.selector
) {
    if (makerBid.additionalParameters.length != 64) {
        return (isValid, OrderInvalid.selector);
    } else {
        (, uint256 transferCooldownPeriod) = abi.decode(makerBid.additionalParameters, (bytes32, uint256));

        // @dev It returns OrderInvalid even if a custom error exists (for order invalidation purposes).
        if (transferCooldownPeriod > MAXIMUM_TRANSFER_COOLDOWN_PERIOD) {
            return (isValid, OrderInvalid.selector);
        }
    }
}

if (makerOrder.quoteType == QuoteType.Bid) {
    validationCodes[5] = _checkValidityMakerBidERC20Assets(makerOrder.currency, makerOrder.signer, price);
} else {
    validationCodes[5] = _checkValidityMakerAskNFTAssets(
        makerOrder.collection,
        makerOrder.collectionType,
        makerOrder.signer,
        itemIds,
        amounts
    );
}

if (ETH_TOKEN_ADDRESS == _token) {
    uint256 amount = address(this).balance;
    bool callSuccess;
    // Low-level assembly call, to avoid any memory copying (save gas)
    assembly {
        callSuccess := call(gas(), ntvAddress, amount, 0, 0, 0, 0)
    }
    if (!callSuccess) {
        revert EthTransferFailed();
    }
} else {
    IERC20(_token).safeTransfer(ntvAddress, IERC20(_token).balanceOf(address(this)));
}

if (block.timestamp < accounts[nftId].bonusDeadline && !accounts[nftId].accountLiquidated) {

    accounts[nftId].fastStartBonus += amount;

    if (accounts[nftId].bonusActive) {

        ITreasury treasury = ITreasury(contractRegistry.getContractAddress(TREASURY_HASH));
        treasury.sendReward(nftId, amount);
    }

    emit FastStartBonusReceived(nftId, from, amount, accounts[nftId].bonusActive);
}

if (supplyCap != 0) {
    uint totalCash = MToken(mToken).getCash();
    uint totalBorrows = MToken(mToken).totalBorrows();
    uint totalReserves = MToken(mToken).totalReserves();
    // totalSupplies = totalCash + totalBorrows - totalReserves
    uint totalSupplies = sub_(
        add_(totalCash, totalBorrows),
        totalReserves
    );

    uint nextTotalSupplies = add_(totalSupplies, mintAmount);
    require(nextTotalSupplies < supplyCap, "market supply cap reached");
}

if (currentPeriod.isOpen()) {
    _ensureSufficientUnderbid(currentPeriod.fee, offeredFee);
    currentPeriod.close(_successionDelay(), _provingWindow());
} else if (nextPeriod.isInitialized()) {
    _ensureSufficientUnderbid(nextPeriod.fee, offeredFee);
    // Refund the liveness bond to the losing bid
    _increaseBalance(nextPeriod.prover, nextPeriod.stake);
}

if (gasLimit == 0) {
    (forwardMessageSuccess,) = to.call{value: valueToSend}(data);
} else {
    // EIP-150: Only 63/64 of gas can be forwarded to external calls.
    // Check against actual forwardable gas with buffer for operations before the call.
    uint256 maxForwardableGas = (gasleft() - BUFFER) * 63 / 64;
    require(gasLimit <= maxForwardableGas, InsufficientGas());
    (forwardMessageSuccess,) = to.call{value: valueToSend, gas: gasLimit}(data);
}

if (!_config[msg.sender].installed) {
    _config[msg.sender].installed = true;
    (uint32 initialDelay, uint32 initialExpiration) = initData.length > 0
        ? abi.decode(initData, (uint32, uint32))
        : (minSetback(), defaultExpiration());
    // An old delay might be still present
    // So we set 0 for the minimum setback relying on any old value as the minimum delay
    _setDelay(msg.sender, initialDelay, 0);
    _setExpiration(msg.sender, initialExpiration);
}

for (uint256 i = 0; i < vestingPlansLength; i++) {
    VestingPlan memory vestingPlan = vestingPlans[i];
    _validateVestingWalletInitArgs(vestingPlan.initArgs);

    address vestingWalletAddress = predictVestingWalletConfidential(vestingPlan.initArgs);

    euint64 encryptedAmount = FHE.fromExternal(vestingPlan.encryptedAmount, inputProof);
    FHE.allowTransient(encryptedAmount, token);
    euint64 transferredAmount = IERC7984(token).confidentialTransferFrom(
        msg.sender,
        vestingWalletAddress,
        encryptedAmount
    );

    emit VestingWalletConfidentialFunded(vestingWalletAddress, token, transferredAmount, vestingPlan.initArgs);
}

if ($._schedules[operationId].timepoint == 0) {
    revert AccessManagerNotScheduled(operationId);
} else if (caller != msgsender) {
    // calls can only be canceled by the account that scheduled them, a global admin, or by a guardian of the required role.
    (bool isAdmin, ) = hasRole(ADMIN_ROLE, msgsender);
    (bool isGuardian, ) = hasRole(getRoleGuardian(getTargetFunctionRole(target, selector)), msgsender);
    if (!isAdmin && !isGuardian) {
        revert AccessManagerUnauthorizedCancel(msgsender, caller, target, selector);
    }
}

if (_schedules[operationId].timepoint == 0) {
    revert AccessManagerNotScheduled(operationId);
} else if (caller != msgsender) {
    // calls can only be canceled by the account that scheduled them, a global admin, or by a guardian of the required role.
    (bool isAdmin, ) = hasRole(ADMIN_ROLE, msgsender);
    (bool isGuardian, ) = hasRole(getRoleGuardian(getTargetFunctionRole(target, selector)), msgsender);
    if (!isAdmin && !isGuardian) {
        revert AccessManagerUnauthorizedCancel(msgsender, caller, target, selector);
    }
}

if (
    SignatureChecker.isValidSignatureNow(
        voter,
        _hashTypedDataV4(
            keccak256(
                abi.encode(BALLOT_TYPEHASH, proposalId, support, voter, nonces(voter, uint192(proposalId)))
            )
        ),
        signature
    )
) {
    _useNonce(voter, uint192(proposalId));
    return true;
} else {
    return super._validateVoteSig(proposalId, support, voter, signature);
}

unchecked {
    uint256 amount0LiquidityPenalty = FullMath.mulDiv(
        SafeCast.toUint128(feeDelta.amount0()),
        blockNumberOffset - (currentBlockNumber - lastAddedLiquidityBlock), // won't overflow.
        blockNumberOffset
    );
    uint256 amount1LiquidityPenalty = FullMath.mulDiv(
        SafeCast.toUint128(feeDelta.amount1()),
        blockNumberOffset - (currentBlockNumber - lastAddedLiquidityBlock), // won't overflow.
        blockNumberOffset
    );

    // Although the amounts are returned as uint256, they must fit in int128, since they are fee rewards.
    liquidityPenalty = toBalanceDelta(amount0LiquidityPenalty.toInt128(), amount1LiquidityPenalty.toInt128());
}

if (!currency.isAddressZero()) {
    IERC20(Currency.unwrap(currency)).safeTransferFrom(sender, address(this), amount);
} else {
    if (msg.value < amount) revert InvalidMsgValue();
    if (msg.value > amount) {
        // slither-disable-next-line arbitrary-send-eth
        (bool success,) = msg.sender.call{value: msg.value - amount}("");
        if (!success) revert RefundFailed();
    }
}

for (uint256 i = 0; i < proposal.transactions.length; i = i.add(1)) {
  bytes4 functionId = ExtractFunctionSignature.extractFunctionSignature(
    proposal.transactions[i].data
  );
  FixidityLib.Fraction memory threshold = _getConstitution(
    proposal.transactions[i].destination,
    functionId
  );
  if (support.lte(threshold)) {
    return false;
  }
}

for (uint256 i = 0; i < identifiersToLookup.length; i = i.add(1)) {
  address[] memory addrs = identifiers[identifiersToLookup[i]].accounts;
  for (uint256 matchIndex = 0; matchIndex < matches[i]; matchIndex = matchIndex.add(1)) {
    addresses[currentIndex] = getAccounts().getWalletAddress(addrs[matchIndex]);
    completed[currentIndex] = identifiers[identifiersToLookup[i]]
      .attestations[addrs[matchIndex]]
      .completed;
    total[currentIndex] = identifiers[identifiersToLookup[i]]
      .attestations[addrs[matchIndex]]
      .requested;
    currentIndex = currentIndex.add(1);
  }
}

ISwapRouter.ExactOutputSingleParams memory params = ISwapRouter.ExactOutputSingleParams({
    tokenIn: apeAsset,
    tokenOut: borrowAsset,
    fee: getBestPool(apeAsset, borrowAsset).fee(),
    recipient: address(this),
    deadline: block.timestamp + 5,
    amountOut: amountOwing,
    amountInMaximum: maxCollateralAmount,
    sqrtPriceLimitX96: 0
});

while ((tree.K * treeIndex) + 1 < tree.nodes.length)  // While it still has children.
            for (uint i = 1; i <= tree.K; i++) { // Loop over children.
                uint nodeIndex = (tree.K * treeIndex) + i;
                uint nodeValue = tree.nodes[nodeIndex];

                if (currentDrawnNumber >= nodeValue) currentDrawnNumber -= nodeValue; // Go to the next child.
                else { // Pick this child.
                    treeIndex = nodeIndex;
                    break;
                }
            }

if (_harvestedAmount > 0) {
  uint256 _feeAmount = _harvestedAmount.mul(harvestFee).div(PERCENT_RESOLUTION);
  uint256 _distributeAmount = _harvestedAmount.sub(_feeAmount);

  FixedPointMath.FixedDecimal memory _weight = FixedPointMath.fromU256(_distributeAmount).div(totalDeposited);
  _ctx.accumulatedYieldWeight = _ctx.accumulatedYieldWeight.add(_weight);

  if (_feeAmount > 0) {
    token.safeTransfer(rewards, _feeAmount);
  }

  if (_distributeAmount > 0) {
    _distributeToTransmuter(_distributeAmount);
  }
}

