    // pending admin pair read/written together frequently
    address _pendingDefaultAdmin;
    uint48 _pendingDefaultAdminSchedule; // 0 == unset

    uint48 _currentDelay;
    address _currentDefaultAdmin;

    // pending delay pair read/written together frequently
    uint48 _pendingDelay;
    uint48 _pendingDelaySchedule; // 0 == unset
}

struct AccessManagerStorage {
    mapping(address target => TargetConfig mode) _targets;
    mapping(uint64 roleId => Role) _roles;
    mapping(bytes32 operationId => Schedule) _schedules;

    // Used to identify operations that are currently being executed via {execute}.
    // This should be transient storage when supported by the EVM.
    bytes32 _executionId;
}

if (timeSinceInitialization < SECONDS_LINEAR) {
  // Pay out half of all block rewards linearly.
  uint256 linearRewards = GOLD_SUPPLY_CAP.sub(GENESIS_GOLD_SUPPLY).div(2);
  uint256 targetRewards = linearRewards.mul(timeSinceInitialization).div(SECONDS_LINEAR);
  return targetRewards.add(GENESIS_GOLD_SUPPLY);
} else {
  require(false, "Block reward calculation for years 15-30 unimplemented");
  return 0;
}

for (uint256 i = 0; i < trustedIssuers.length; i = i.add(1)) {
  attestationsPerIssuer = identifierToAttestations[identifier][trustedIssuers[i]];
  for (uint256 j = 0; j < attestationsPerIssuer.length; j = j.add(1)) {
    accounts[totalAttestations] = attestationsPerIssuer[j].account;
    signers[totalAttestations] = attestationsPerIssuer[j].signer;
    issuedOns[totalAttestations] = attestationsPerIssuer[j].issuedOn;
    publishedOns[totalAttestations] = attestationsPerIssuer[j].publishedOn;
    totalAttestations = totalAttestations.add(1);
  }
}

